/**
 * Nav — single-spa parcel entry.
 *
 * The Nav app is not route-based. It mounts as a parcel inside
 * AppLayout of every other microfrontend via mountRootParcel().
 * Props passed by the host app: { user, onLogout, onNavigate }
 */
import React from 'react';
import singleSpaReact from 'single-spa-react';
import { createRoot } from 'react-dom/client';
import NavRoot from './NavRoot';

const lifecycles = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: NavRoot as any,
  errorBoundary(_error: Error, _info: React.ErrorInfo, _props: unknown) {
    return <nav style={{ background: '#1e3a5f', height: '100%' }} />;
  },
  renderType: 'createRoot',
});

export const { bootstrap, mount, unmount } = lifecycles;
